<!doctype html>
<html lang="zh-CN"><head>
<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Artdon BOM · 命名系统产品联动</title>
<style>
:root{--bg:#f5f7fb;--card:#fff;--text:#172033;--muted:#667085;--line:#dbe3f0;--blue:#2563eb;--green:#16a34a;--red:#dc2626;--amber:#d97706}
*{box-sizing:border-box}body{margin:0;background:linear-gradient(180deg,#f8fbff,#eef3fb);font-family:-apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",Arial,sans-serif;color:var(--text)}
.header{position:sticky;top:0;z-index:10;background:rgba(255,255,255,.92);border-bottom:1px solid var(--line);backdrop-filter:blur(10px)}.inner{padding:16px 20px;max-width:1480px;margin:auto}.top{display:flex;justify-content:space-between;gap:14px;align-items:center}.title h1{font-size:22px;margin:0}.title p{margin:4px 0 0;color:var(--muted);font-size:13px}.nav{display:flex;gap:8px;flex-wrap:wrap}.btn{border:1px solid var(--line);background:#fff;color:#111827;border-radius:10px;padding:9px 13px;text-decoration:none;font-weight:700;cursor:pointer}.btn.primary{background:var(--blue);border-color:var(--blue);color:white}.btn.green{background:var(--green);border-color:var(--green);color:white}.btn.red{background:var(--red);border-color:var(--red);color:white}.btn.ghost{background:#f8fafc}.wrap{max-width:1480px;margin:18px auto;padding:0 20px}.panel{background:var(--card);border:1px solid var(--line);border-radius:18px;box-shadow:0 12px 30px rgba(15,23,42,.06);padding:16px}.toolbar{display:grid;grid-template-columns:1fr auto auto auto;gap:10px;align-items:center}.toolbar input{width:100%;border:1px solid var(--line);border-radius:12px;padding:12px 14px;font-size:15px}.hint{color:var(--muted);font-size:13px;margin-top:10px}.grid{display:grid;grid-template-columns:repeat(5,minmax(190px,1fr));gap:14px;margin-top:16px}.card{background:#fff;border:1px solid var(--line);border-radius:16px;overflow:hidden;box-shadow:0 6px 18px rgba(15,23,42,.045);display:flex;flex-direction:column;min-height:300px}.pic{height:132px;background:linear-gradient(135deg,#f8fafc,#f1f5f9);display:flex;align-items:center;justify-content:center;border-bottom:1px solid #edf2f7}.pic img{max-width:100%;max-height:126px;object-fit:contain}.placeholder{color:#94a3b8;font-weight:800;font-size:28px}.body{padding:12px;display:flex;flex-direction:column;gap:7px;flex:1}.model{font-size:18px;font-weight:900;line-height:1.2}.sub{font-size:13px;color:var(--muted);line-height:1.35}.tags{display:flex;gap:6px;flex-wrap:wrap}.tag{font-size:12px;border-radius:999px;padding:3px 8px;background:#eef2ff;color:#3730a3;border:1px solid #c7d2fe}.tag.ok{background:#ecfdf5;color:#166534;border-color:#bbf7d0}.tag.warn{background:#fff7ed;color:#9a3412;border-color:#fed7aa}.actions{display:flex;gap:7px;flex-wrap:wrap;margin-top:auto}.small{font-size:12px;padding:7px 9px;border-radius:9px}.empty{padding:60px 20px;text-align:center;color:var(--muted);font-size:15px}.statusbar{margin-top:12px;color:var(--muted);font-size:13px}.toast{position:fixed;right:18px;bottom:18px;background:#111827;color:#fff;padding:12px 14px;border-radius:12px;box-shadow:0 14px 30px rgba(0,0,0,.25);display:none;z-index:99;max-width:460px;line-height:1.45}.modalMask{position:fixed;inset:0;background:rgba(15,23,42,.45);display:none;align-items:center;justify-content:center;z-index:50}.modal{background:#fff;border-radius:18px;border:1px solid var(--line);width:min(760px,92vw);padding:18px;box-shadow:0 30px 80px rgba(0,0,0,.25)}.modal h3{margin:0 0 8px}.modal pre{white-space:pre-wrap;background:#f8fafc;border:1px solid var(--line);border-radius:12px;padding:12px;max-height:280px;overflow:auto}@media(max-width:1180px){.grid{grid-template-columns:repeat(4,1fr)}}@media(max-width:900px){.grid{grid-template-columns:repeat(2,1fr)}.toolbar{grid-template-columns:1fr 1fr}.top{align-items:flex-start;flex-direction:column}}@media(max-width:560px){.grid{grid-template-columns:1fr}.toolbar{grid-template-columns:1fr}}
</style></head><body>
<header class="header"><div class="inner"><div class="top"><div class="title"><h1>Artdon BOM · 命名系统产品联动</h1><p>从命名系统选择产品 → 建立/打开 BOM 成本单 → 报价系统再按型号精准取 BOM 总成本</p></div><div class="nav"><a class="btn" href="artdon_portal.php">首页</a><a class="btn" href="naming.php">命名系统</a><a class="btn" href="bom.php">BOM</a><a class="btn" href="quotation.php">报价</a></div></div></div></header>
<main class="wrap"><section class="panel"><div class="toolbar"><input id="kw" placeholder="搜索型号 / 产品名 / 分类 / 客户，例如 95.01012" onkeydown="if(event.key==='Enter')loadList()"><button class="btn primary" onclick="loadList()">搜索</button><button class="btn ghost" onclick="init()">初始化</button><button class="btn ghost" onclick="debugSchema()">诊断</button></div><div class="hint">说明：命名产品只读；BOM 成本单会保存 naming_id + product_model，后续报价系统优先按这个绑定取成本，不再靠模糊猜。</div><div id="status" class="statusbar">准备就绪</div><div id="grid" class="grid"></div></section></main>
<div id="toast" class="toast"></div><div id="modalMask" class="modalMask" onclick="closeModal(event)"><div class="modal"><h3 id="modalTitle">提示</h3><pre id="modalText"></pre><div style="display:flex;justify-content:flex-end;gap:8px;margin-top:12px"><button class="btn" onclick="hideModal()">关闭</button></div></div></div>
<script>
const API='bom_naming_link_api.php';
const $=id=>document.getElementById(id); const esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
function toast(s){const t=$('toast');t.textContent=s;t.style.display='block';setTimeout(()=>t.style.display='none',4200)}
async function api(action,data={}){const r=await fetch(API+'?action='+encodeURIComponent(action),{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});return await r.json()}
function img(src){src=String(src||'').trim(); if(!src) return '<div class="placeholder">N</div>'; return '<img src="'+esc(src)+'" onerror="this.outerHTML=\'<div class=&quot;placeholder&quot;>N</div>\'">'}
function bomTag(r){return r.has_bom?'<span class="tag ok">已建 BOM</span>':'<span class="tag warn">未建 BOM</span>'}
function card(r){const ex=r.bom_existing||{};const total=ex.total_cost?('RMB '+Number(ex.total_cost).toFixed(2)):'';return `<div class="card"><div class="pic">${img(r.image_path)}</div><div class="body"><div class="tags"><span class="tag">命名中心</span>${bomTag(r)}${total?`<span class="tag ok">${esc(total)}</span>`:''}</div><div class="model">${esc(r.model_no||'-')}</div><div class="sub"><b>${esc(r.product_name||r.item_name||'未命名产品')}</b></div><div class="sub">${esc(r.category||'未分类')} ｜ ${esc(r.item_name||'')}</div><div class="sub">${esc(r.dim_summary||r.size_code||'')}</div>${ex.project_uid?`<div class="sub">已有：${esc(ex.name||ex.project_uid)}</div>`:''}<div class="actions"><button class="btn primary small" onclick="createBom(${+r.id},'open_or_create')">${r.has_bom?'打开现有':'新建 BOM'}</button><button class="btn ghost small" onclick="createBom(${+r.id},'new')">强制新建</button><button class="btn ghost small" onclick="createBom(${+r.id},'copy')">复制旧BOM</button></div></div></div>`}
async function init(){const r=await api('init'); if(!r.ok){toast(r.error||'初始化失败');return} toast('初始化完成'); $('status').textContent=r.message||'初始化完成';}
async function loadList(){ $('status').textContent='读取命名产品中...'; const r=await api('list_naming',{q:$('kw').value,limit:120}); if(!r.ok){$('grid').innerHTML='<div class="empty">'+esc(r.error||'读取失败')+'</div>'; return} $('status').textContent='共 '+r.count+' 个命名产品'; $('grid').innerHTML=r.rows.length?r.rows.map(card).join(''):'<div class="empty">没有找到命名产品</div>'; }
async function createBom(id,mode){ const r=await api('create_bom_from_naming',{naming_id:id,mode}); if(!r.ok){toast(r.error||'操作失败');return} const p=r.project||{}; toast(r.message||'完成'); showModal('BOM 成本单已准备好',`型号：${p.model||''}\nBOM UID：${p.project_uid||''}\n名称：${p.name||''}\n\n下一步：点击“打开 BOM”，在 BOM 成本单列表中搜索这个型号或 UID，然后继续补全物料成本。`); loadList(); setTimeout(()=>{ if(confirm('是否现在打开 BOM 页面？')) window.open('bom.php','_blank'); },400); }
async function debugSchema(){const r=await api('schema_debug'); showModal('数据库结构诊断',JSON.stringify(r,null,2));}
function showModal(t,s){$('modalTitle').textContent=t;$('modalText').textContent=s;$('modalMask').style.display='flex'} function hideModal(){$('modalMask').style.display='none'} function closeModal(e){if(e.target.id==='modalMask')hideModal()}
init().then(loadList);
</script></body></html>
